import { useState, useEffect, useRef, useCallback } from 'react';
import { Play, RotateCcw, Send, Loader2, Save } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';

interface CodeEditorProps {
  initialCode?: string;
  language: string;
  onSubmit: (code: string) => void;
  onRun?: (code: string) => void;
  readOnly?: boolean;
  submitting?: boolean;
}

export function CodeEditor({ initialCode = '', language, onSubmit, onRun, readOnly = false, submitting = false }: CodeEditorProps) {
  const [code, setCode] = useState(initialCode);
  const [output, setOutput] = useState<string>('');
  const [running, setRunning] = useState(false);
  const [autoSaved, setAutoSaved] = useState(false);
  const autoSaveRef = useRef<ReturnType<typeof setTimeout>>();
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Auto-save to localStorage every 3 seconds of inactivity
  useEffect(() => {
    if (readOnly) return;
    if (autoSaveRef.current) clearTimeout(autoSaveRef.current);
    autoSaveRef.current = setTimeout(() => {
      const key = `codehub_draft_${language}_${initialCode.slice(0, 20)}`;
      localStorage.setItem(key, code);
      setAutoSaved(true);
      setTimeout(() => setAutoSaved(false), 1500);
    }, 3000);
    return () => { if (autoSaveRef.current) clearTimeout(autoSaveRef.current); };
  }, [code, language, initialCode, readOnly, autoSaveRef]);

  // Restore draft on mount
  useEffect(() => {
    const key = `codehub_draft_${language}_${initialCode.slice(0, 20)}`;
    const saved = localStorage.getItem(key);
    if (saved && saved !== initialCode) {
      setCode(saved);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleRun = async () => {
    setRunning(true);
    setOutput('Running code...\n');

    try {
      const { data, error } = await supabase.functions.invoke('execute-code', {
        body: { code, language },
      });

      if (error) throw error;

      if (data?.stderr) {
        setOutput(`Error:\n${data.stderr}\n\nExecution time: ${data.executionTime}ms`);
      } else {
        setOutput(`${data?.output || 'No output'}\n\nExecution time: ${data?.executionTime || 0}ms`);
      }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    } catch (err: any) {
      setOutput(`Error: ${err.message || 'Failed to execute code'}`);
    }

    setRunning(false);
    onRun?.(code);
  };

  const handleReset = () => {
    setCode(initialCode);
    setOutput('');
    const key = `codehub_draft_${language}_${initialCode.slice(0, 20)}`;
    localStorage.removeItem(key);
  };

  const handleSubmit = () => {
    onSubmit(code);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const textarea = e.target as HTMLTextAreaElement;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      setCode(code.substring(0, start) + '  ' + code.substring(end));
      setTimeout(() => {
        textarea.selectionStart = textarea.selectionEnd = start + 2;
      }, 0);
    }
    if (e.ctrlKey && e.key === 'Enter') {
      e.preventDefault();
      handleRun();
    }
    if (e.ctrlKey && e.key === 's') {
      e.preventDefault();
      // Manual save
      const key = `codehub_draft_${language}_${initialCode.slice(0, 20)}`;
      localStorage.setItem(key, code);
      setAutoSaved(true);
      setTimeout(() => setAutoSaved(false), 1500);
    }
  };

  const getLanguageColor = () => {
    const colors: Record<string, string> = {
      javascript: 'bg-warning-light text-warning',
      python: 'bg-info-light text-primary',
      java: 'bg-warning-light text-warning',
      cpp: 'bg-secondary text-foreground',
      'c++': 'bg-secondary text-foreground',
      c: 'bg-secondary text-foreground',
      go: 'bg-info-light text-primary',
      rust: 'bg-error-light text-error',
      typescript: 'bg-info-light text-primary',
    };
    return colors[language.toLowerCase()] || 'bg-secondary text-secondary-foreground';
  };

  return (
    <div className="flex flex-col h-full">
      <div className="flex items-center justify-between bg-secondary/50 px-4 py-2 rounded-t-lg border border-border">
        <div className="flex items-center gap-2">
          <span className={`text-xs font-medium px-2 py-1 rounded ${getLanguageColor()}`}>{language}</span>
          {autoSaved && (
            <span className="text-xs text-muted-foreground flex items-center gap-1 animate-in fade-in">
              <Save className="w-3 h-3" /> Saved
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleReset} className="p-2 hover:bg-secondary rounded-lg transition-colors text-muted-foreground hover:text-foreground" title="Reset code (Ctrl+Shift+R)">
            <RotateCcw className="w-4 h-4" />
          </button>
          <button onClick={handleRun} disabled={running} className="flex items-center gap-2 px-3 py-1.5 bg-secondary hover:bg-secondary/80 rounded-lg transition-colors text-sm font-medium disabled:opacity-50">
            {running ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4" />}
            {running ? 'Running...' : 'Run'}
          </button>
          <button onClick={handleSubmit} disabled={submitting} className="flex items-center gap-2 px-3 py-1.5 bg-primary text-primary-foreground rounded-lg transition-colors text-sm font-medium hover:bg-primary/90 disabled:opacity-50">
            {submitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
            {submitting ? 'Submitting...' : 'Submit'}
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row gap-0 border-x border-border">
        <div className="flex-1 relative">
          <div className="absolute left-0 top-0 bottom-0 w-12 bg-code border-r border-code-border flex flex-col items-end py-4 pr-2 text-xs text-muted-foreground font-mono select-none">
            {code.split('\n').map((_, i) => (<div key={i} className="leading-6">{i + 1}</div>))}
          </div>
          <textarea
            ref={textareaRef}
            value={code}
            onChange={(e) => setCode(e.target.value)}
            onKeyDown={handleKeyDown}
            className="w-full h-full min-h-[300px] pl-14 pr-4 py-4 bg-code font-mono text-sm text-foreground resize-none focus:outline-none leading-6"
            spellCheck={false}
            readOnly={readOnly}
            placeholder="Write your code here..."
          />
        </div>

        <div className="lg:w-80 border-t lg:border-t-0 lg:border-l border-border">
          <div className="bg-secondary/50 px-4 py-2 border-b border-border">
            <span className="text-sm font-medium text-foreground">Output</span>
          </div>
          <div className="p-4 bg-code min-h-[150px] font-mono text-sm text-muted-foreground whitespace-pre-wrap">
            {output || 'Run your code to see output here...'}
          </div>
        </div>
      </div>

      <div className="bg-secondary/50 px-4 py-2 rounded-b-lg border border-t-0 border-border text-xs text-muted-foreground flex items-center justify-between">
        <span>Ctrl+Enter to run • Ctrl+S to save • Tab for indentation</span>
        <span>{code.split('\n').length} lines</span>
      </div>
    </div>
  );
}

import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Code2, LogOut, User, Trophy } from 'lucide-react';

export function Navbar() {
  const { user, logout, isAuthenticated } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  const getNavLinks = () => {
    if (!user) return [];

    const common = [
      { path: '/leaderboard', label: 'Leaderboard' },
    ];

    switch (user.role) {
      case 'teacher':
        return [
          { path: '/teacher/dashboard', label: 'Dashboard' },
          { path: '/teacher/assessments', label: 'Assessments' },
          { path: '/teacher/create', label: 'Create' },
          { path: '/teacher/workspace', label: 'Workspace' },
          { path: '/teacher/students', label: 'Students' },
          ...common,
        ];
      case 'student':
        return [
          { path: '/student/dashboard', label: 'Dashboard' },
          { path: '/student/assessments', label: 'Assessments' },
          { path: '/student/progress', label: 'Progress' },
          ...common,
        ];
      case 'professional':
        return [
          { path: '/professional/dashboard', label: 'Dashboard' },
          { path: '/professional/practice', label: 'Practice' },
          { path: '/professional/challenges', label: 'Challenges' },
          ...common,
        ];
      default:
        return common;
    }
  };

  const isActive = (path: string) => location.pathname === path;

  return (
    <nav className="bg-card border-b border-border sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <Link to="/" className="flex items-center gap-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <Code2 className="w-5 h-5 text-primary-foreground" />
            </div>
            <span className="text-xl font-bold text-foreground">CodeHub</span>
          </Link>

          {isAuthenticated && (
            <div className="hidden md:flex items-center gap-1">
              {getNavLinks().map((link) => (
                <Link
                  key={link.path}
                  to={link.path}
                  className={`nav-link ${isActive(link.path) ? 'nav-link-active' : ''}`}
                >
                  {link.label}
                </Link>
              ))}
            </div>
          )}

          <div className="flex items-center gap-4">
            {isAuthenticated ? (
              <>
                <Link
                  to="/profile"
                  className="hidden sm:flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground transition-colors"
                >
                  <div className="w-7 h-7 bg-primary/10 rounded-full flex items-center justify-center">
                    <span className="text-xs font-bold text-primary">{user?.name?.charAt(0)?.toUpperCase()}</span>
                  </div>
                  <span>{user?.name}</span>
                  <span className="px-2 py-0.5 bg-secondary rounded-full text-xs capitalize">
                    {user?.role}
                  </span>
                </Link>
                <button
                  onClick={handleLogout}
                  className="flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors"
                >
                  <LogOut className="w-4 h-4" />
                  <span className="hidden sm:inline">Logout</span>
                </button>
              </>
            ) : (
              <Link to="/login" className="btn-primary">
                Sign In
              </Link>
            )}
          </div>
        </div>

        {/* Mobile navigation */}
        {isAuthenticated && (
          <div className="md:hidden flex overflow-x-auto pb-2 -mx-4 px-4 gap-1">
            {getNavLinks().map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`nav-link whitespace-nowrap text-sm ${isActive(link.path) ? 'nav-link-active' : ''}`}
              >
                {link.label}
              </Link>
            ))}
          </div>
        )}
      </div>
    </nav>
  );
}

import * as React from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { DayPicker } from "react-day-picker";

import { cn } from "@/lib/utils";
import { buttonVariants } from "@/components/ui/button";

export type CalendarProps = React.ComponentProps<typeof DayPicker>;

function Calendar({ className, classNames, showOutsideDays = true, ...props }: CalendarProps) {
  return (
    <DayPicker
      showOutsideDays={showOutsideDays}
      className={cn("p-3", className)}
      classNames={{
        months: "flex flex-col sm:flex-row space-y-4 sm:space-x-4 sm:space-y-0",
        month: "space-y-4",
        caption: "flex justify-center pt-1 relative items-center",
        caption_label: "text-sm font-medium",
        nav: "space-x-1 flex items-center",
        nav_button: cn(
          buttonVariants({ variant: "outline" }),
          "h-7 w-7 bg-transparent p-0 opacity-50 hover:opacity-100",
        ),
        nav_button_previous: "absolute left-1",
        nav_button_next: "absolute right-1",
        table: "w-full border-collapse space-y-1",
        head_row: "flex",
        head_cell: "text-muted-foreground rounded-md w-9 font-normal text-[0.8rem]",
        row: "flex w-full mt-2",
        cell: "h-9 w-9 text-center text-sm p-0 relative [&:has([aria-selected].day-range-end)]:rounded-r-md [&:has([aria-selected].day-outside)]:bg-accent/50 [&:has([aria-selected])]:bg-accent first:[&:has([aria-selected])]:rounded-l-md last:[&:has([aria-selected])]:rounded-r-md focus-within:relative focus-within:z-20",
        day: cn(buttonVariants({ variant: "ghost" }), "h-9 w-9 p-0 font-normal aria-selected:opacity-100"),
        day_range_end: "day-range-end",
        day_selected:
          "bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground focus:bg-primary focus:text-primary-foreground",
        day_today: "bg-accent text-accent-foreground",
        day_outside:
          "day-outside text-muted-foreground opacity-50 aria-selected:bg-accent/50 aria-selected:text-muted-foreground aria-selected:opacity-30",
        day_disabled: "text-muted-foreground opacity-50",
        day_range_middle: "aria-selected:bg-accent aria-selected:text-accent-foreground",
        day_hidden: "invisible",
        ...classNames,
      }}
      components={{
        IconLeft: ({ ..._props }) => <ChevronLeft className="h-4 w-4" />,
        IconRight: ({ ..._props }) => <ChevronRight className="h-4 w-4" />,
      }}
      {...props}
    />
  );
}
Calendar.displayName = "Calendar";

export { Calendar };

import * as React from "react";
import * as RechartsPrimitive from "recharts";

import { cn } from "@/lib/utils";

// Format: { THEME_NAME: CSS_SELECTOR }
const THEMES = { light: "", dark: ".dark" } as const;

export type ChartConfig = {
  [k in string]: {
    label?: React.ReactNode;
    icon?: React.ComponentType;
  } & ({ color?: string; theme?: never } | { color?: never; theme: Record<keyof typeof THEMES, string> });
};

type ChartContextProps = {
  config: ChartConfig;
};

const ChartContext = React.createContext<ChartContextProps | null>(null);

function useChart() {
  const context = React.useContext(ChartContext);

  if (!context) {
    throw new Error("useChart must be used within a <ChartContainer />");
  }

  return context;
}

const ChartContainer = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    config: ChartConfig;
    children: React.ComponentProps<typeof RechartsPrimitive.ResponsiveContainer>["children"];
  }
>(({ id, className, children, config, ...props }, ref) => {
  const uniqueId = React.useId();
  const chartId = `chart-${id || uniqueId.replace(/:/g, "")}`;

  return (
    <ChartContext.Provider value={{ config }}>
      <div
        data-chart={chartId}
        ref={ref}
        className={cn(
          "flex aspect-video justify-center text-xs [&_.recharts-cartesian-axis-tick_text]:fill-muted-foreground [&_.recharts-cartesian-grid_line[stroke='#ccc']]:stroke-border/50 [&_.recharts-curve.recharts-tooltip-cursor]:stroke-border [&_.recharts-dot[stroke='#fff']]:stroke-transparent [&_.recharts-layer]:outline-none [&_.recharts-polar-grid_[stroke='#ccc']]:stroke-border [&_.recharts-radial-bar-background-sector]:fill-muted [&_.recharts-rectangle.recharts-tooltip-cursor]:fill-muted [&_.recharts-reference-line_[stroke='#ccc']]:stroke-border [&_.recharts-sector[stroke='#fff']]:stroke-transparent [&_.recharts-sector]:outline-none [&_.recharts-surface]:outline-none",
          className,
        )}
        {...props}
      >
        <ChartStyle id={chartId} config={config} />
        <RechartsPrimitive.ResponsiveContainer>{children}</RechartsPrimitive.ResponsiveContainer>
      </div>
    </ChartContext.Provider>
  );
});
ChartContainer.displayName = "Chart";

const ChartStyle = ({ id, config }: { id: string; config: ChartConfig }) => {
  const colorConfig = Object.entries(config).filter(([_, config]) => config.theme || config.color);

  if (!colorConfig.length) {
    return null;
  }

  return (
    <style
      dangerouslySetInnerHTML={{
        __html: Object.entries(THEMES)
          .map(
            ([theme, prefix]) => `
${prefix} [data-chart=${id}] {
${colorConfig
  .map(([key, itemConfig]) => {
    const color = itemConfig.theme?.[theme as keyof typeof itemConfig.theme] || itemConfig.color;
    return color ? `  --color-${key}: ${color};` : null;
  })
  .join("\n")}
}
`,
          )
          .join("\n"),
      }}
    />
  );
};

const ChartTooltip = RechartsPrimitive.Tooltip;

const ChartTooltipContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<typeof RechartsPrimitive.Tooltip> &
    React.ComponentProps<"div"> & {
      hideLabel?: boolean;
      hideIndicator?: boolean;
      indicator?: "line" | "dot" | "dashed";
      nameKey?: string;
      labelKey?: string;
    }
>(
  (
    {
      active,
      payload,
      className,
      indicator = "dot",
      hideLabel = false,
      hideIndicator = false,
      label,
      labelFormatter,
      labelClassName,
      formatter,
      color,
      nameKey,
      labelKey,
    },
    ref,
  ) => {
    const { config } = useChart();

    const tooltipLabel = React.useMemo(() => {
      if (hideLabel || !payload?.length) {
        return null;
      }

      const [item] = payload;
      const key = `${labelKey || item.dataKey || item.name || "value"}`;
      const itemConfig = getPayloadConfigFromPayload(config, item, key);
      const value =
        !labelKey && typeof label === "string"
          ? config[label as keyof typeof config]?.label || label
          : itemConfig?.label;

      if (labelFormatter) {
        return <div className={cn("font-medium", labelClassName)}>{labelFormatter(value, payload)}</div>;
      }

      if (!value) {
        return null;
      }

      return <div className={cn("font-medium", labelClassName)}>{value}</div>;
    }, [label, labelFormatter, payload, hideLabel, labelClassName, config, labelKey]);

    if (!active || !payload?.length) {
      return null;
    }

    const nestLabel = payload.length === 1 && indicator !== "dot";

    return (
      <div
        ref={ref}
        className={cn(
          "grid min-w-[8rem] items-start gap-1.5 rounded-lg border border-border/50 bg-background px-2.5 py-1.5 text-xs shadow-xl",
          className,
        )}
      >
        {!nestLabel ? tooltipLabel : null}
        <div className="grid gap-1.5">
          {payload.map((item, index) => {
            const key = `${nameKey || item.name || item.dataKey || "value"}`;
            const itemConfig = getPayloadConfigFromPayload(config, item, key);
            const indicatorColor = color || item.payload.fill || item.color;

            return (
              <div
                key={item.dataKey}
                className={cn(
                  "flex w-full flex-wrap items-stretch gap-2 [&>svg]:h-2.5 [&>svg]:w-2.5 [&>svg]:text-muted-foreground",
                  indicator === "dot" && "items-center",
                )}
              >
                {formatter && item?.value !== undefined && item.name ? (
                  formatter(item.value, item.name, item, index, item.payload)
                ) : (
                  <>
                    {itemConfig?.icon ? (
                      <itemConfig.icon />
                    ) : (
                      !hideIndicator && (
                        <div
                          className={cn("shrink-0 rounded-[2px] border-[--color-border] bg-[--color-bg]", {
                            "h-2.5 w-2.5": indicator === "dot",
                            "w-1": indicator === "line",
                            "w-0 border-[1.5px] border-dashed bg-transparent": indicator === "dashed",
                            "my-0.5": nestLabel && indicator === "dashed",
                          })}
                          style={
                            {
                              "--color-bg": indicatorColor,
                              "--color-border": indicatorColor,
                            } as React.CSSProperties
                          }
                        />
                      )
                    )}
                    <div
                      className={cn(
                        "flex flex-1 justify-between leading-none",
                        nestLabel ? "items-end" : "items-center",
                      )}
                    >
                      <div className="grid gap-1.5">
                        {nestLabel ? tooltipLabel : null}
                        <span className="text-muted-foreground">{itemConfig?.label || item.name}</span>
                      </div>
                      {item.value && (
                        <span className="font-mono font-medium tabular-nums text-foreground">
                          {item.value.toLocaleString()}
                        </span>
                      )}
                    </div>
                  </>
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  },
);
ChartTooltipContent.displayName = "ChartTooltip";

const ChartLegend = RechartsPrimitive.Legend;

const ChartLegendContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> &
    Pick<RechartsPrimitive.LegendProps, "payload" | "verticalAlign"> & {
      hideIcon?: boolean;
      nameKey?: string;
    }
>(({ className, hideIcon = false, payload, verticalAlign = "bottom", nameKey }, ref) => {
  const { config } = useChart();

  if (!payload?.length) {
    return null;
  }

  return (
    <div
      ref={ref}
      className={cn("flex items-center justify-center gap-4", verticalAlign === "top" ? "pb-3" : "pt-3", className)}
    >
      {payload.map((item) => {
        const key = `${nameKey || item.dataKey || "value"}`;
        const itemConfig = getPayloadConfigFromPayload(config, item, key);

        return (
          <div
            key={item.value}
            className={cn("flex items-center gap-1.5 [&>svg]:h-3 [&>svg]:w-3 [&>svg]:text-muted-foreground")}
          >
            {itemConfig?.icon && !hideIcon ? (
              <itemConfig.icon />
            ) : (
              <div
                className="h-2 w-2 shrink-0 rounded-[2px]"
                style={{
                  backgroundColor: item.color,
                }}
              />
            )}
            {itemConfig?.label}
          </div>
        );
      })}
    </div>
  );
});
ChartLegendContent.displayName = "ChartLegend";

// Helper to extract item config from a payload.
function getPayloadConfigFromPayload(config: ChartConfig, payload: unknown, key: string) {
  if (typeof payload !== "object" || payload === null) {
    return undefined;
  }

  const payloadPayload =
    "payload" in payload && typeof payload.payload === "object" && payload.payload !== null
      ? payload.payload
      : undefined;

  let configLabelKey: string = key;

  if (key in payload && typeof payload[key as keyof typeof payload] === "string") {
    configLabelKey = payload[key as keyof typeof payload] as string;
  } else if (
    payloadPayload &&
    key in payloadPayload &&
    typeof payloadPayload[key as keyof typeof payloadPayload] === "string"
  ) {
    configLabelKey = payloadPayload[key as keyof typeof payloadPayload] as string;
  }

  return configLabelKey in config ? config[configLabelKey] : config[key as keyof typeof config];
}

export { ChartContainer, ChartTooltip, ChartTooltipContent, ChartLegend, ChartLegendContent, ChartStyle };

import * as React from "react";

import type { ToastActionElement, ToastProps } from "@/components/ui/toast";

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType["ADD_TOAST"];
      toast: ToasterToast;
    }
  | {
      type: ActionType["UPDATE_TOAST"];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType["DISMISS_TOAST"];
      toastId?: ToasterToast["id"];
    }
  | {
      type: ActionType["REMOVE_TOAST"];
      toastId?: ToasterToast["id"];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) => (t.id === action.toast.id ? { ...t, ...action.toast } : t)),
      };

    case "DISMISS_TOAST": {
      const { toastId } = action;

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      };
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, "id">;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    });
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id });

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss();
      },
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  };
}

export { useToast, toast };

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Trophy, Medal, Award, TrendingUp, Users } from 'lucide-react';
import { Navbar } from '@/components/Navbar';

interface LeaderboardEntry {
  user_id: string;
  name: string;
  total_submissions: number;
  correct_submissions: number;
  accuracy: number;
}

export default function Leaderboard() {
  const [entries, setEntries] = useState<LeaderboardEntry[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchLeaderboard() {
      // Fetch all submissions
      const { data: submissions } = await supabase
        .from('submissions')
        .select('student_id, is_correct');

      if (!submissions) { setLoading(false); return; }

      // Aggregate by student
      const statsMap: Record<string, { total: number; correct: number }> = {};
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      submissions.forEach((s: any) => {
        if (!statsMap[s.student_id]) statsMap[s.student_id] = { total: 0, correct: 0 };
        statsMap[s.student_id].total++;
        if (s.is_correct) statsMap[s.student_id].correct++;
      });

      // Fetch profiles
      const userIds = Object.keys(statsMap);
      if (userIds.length === 0) { setLoading(false); return; }

      const { data: profiles } = await supabase
        .from('profiles')
        .select('user_id, name')
        .in('user_id', userIds);

      const profileMap: Record<string, string> = {};
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (profiles || []).forEach((p: any) => { profileMap[p.user_id] = p.name; });

      const leaderboard = userIds.map(uid => ({
        user_id: uid,
        name: profileMap[uid] || 'Unknown',
        total_submissions: statsMap[uid].total,
        correct_submissions: statsMap[uid].correct,
        accuracy: statsMap[uid].total > 0 ? (statsMap[uid].correct / statsMap[uid].total) * 100 : 0,
      }));

      // Sort by correct submissions desc, then accuracy
      leaderboard.sort((a, b) => b.correct_submissions - a.correct_submissions || b.accuracy - a.accuracy);

      setEntries(leaderboard);
      setLoading(false);
    }

    fetchLeaderboard();
  }, []);

  const getRankIcon = (index: number) => {
    if (index === 0) return <Trophy className="w-6 h-6 text-warning" />;
    if (index === 1) return <Medal className="w-6 h-6 text-muted-foreground" />;
    if (index === 2) return <Award className="w-6 h-6 text-warning" style={{ opacity: 0.7 }} />;
    return <span className="w-6 h-6 flex items-center justify-center text-sm font-bold text-muted-foreground">{index + 1}</span>;
  };

  return (
    <>
      <Navbar />
      <div className="page-container">
        <div className="flex items-center gap-3 mb-8">
          <div className="w-12 h-12 bg-warning-light rounded-xl flex items-center justify-center">
            <Trophy className="w-7 h-7 text-warning" />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-foreground">Leaderboard</h1>
            <p className="text-muted-foreground">Top performers across all assessments</p>
          </div>
        </div>

        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-8 h-8 border-2 border-primary border-t-transparent rounded-full animate-spin" />
          </div>
        ) : entries.length > 0 ? (
          <>
            {/* Top 3 cards */}
            {entries.length >= 3 && (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
                {entries.slice(0, 3).map((entry, i) => (
                  <div key={entry.user_id} className={`card-elevated text-center ${i === 0 ? 'border-warning/50 bg-warning-light/30' : ''}`}>
                    <div className="mb-3">{getRankIcon(i)}</div>
                    <div className="w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-3">
                      <span className="text-2xl font-bold text-primary">{entry.name.charAt(0).toUpperCase()}</span>
                    </div>
                    <h3 className="font-semibold text-foreground">{entry.name}</h3>
                    <p className="text-3xl font-bold text-primary mt-2">{entry.correct_submissions}</p>
                    <p className="text-sm text-muted-foreground">problems solved</p>
                    <p className="text-sm font-medium text-easy mt-1">{entry.accuracy.toFixed(0)}% accuracy</p>
                  </div>
                ))}
              </div>
            )}

            {/* Full table */}
            <div className="card-elevated overflow-hidden p-0">
              <table className="w-full">
                <thead className="bg-secondary/50 border-b border-border">
                  <tr>
                    <th className="text-left px-6 py-4 text-sm font-semibold text-foreground">Rank</th>
                    <th className="text-left px-6 py-4 text-sm font-semibold text-foreground">Name</th>
                    <th className="text-center px-6 py-4 text-sm font-semibold text-foreground">Solved</th>
                    <th className="text-center px-6 py-4 text-sm font-semibold text-foreground">Total</th>
                    <th className="text-center px-6 py-4 text-sm font-semibold text-foreground">Accuracy</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {entries.map((entry, i) => (
                    <tr key={entry.user_id} className={`hover:bg-secondary/30 transition-colors ${i < 3 ? 'bg-warning-light/10' : ''}`}>
                      <td className="px-6 py-4">{getRankIcon(i)}</td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                            <span className="text-sm font-bold text-primary">{entry.name.charAt(0).toUpperCase()}</span>
                          </div>
                          <span className="font-medium text-foreground">{entry.name}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center font-semibold text-easy">{entry.correct_submissions}</td>
                      <td className="px-6 py-4 text-center text-foreground">{entry.total_submissions}</td>
                      <td className="px-6 py-4 text-center">
                        <span className={`font-medium ${entry.accuracy >= 70 ? 'text-easy' : entry.accuracy >= 40 ? 'text-warning' : 'text-error'}`}>
                          {entry.accuracy.toFixed(0)}%
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        ) : (
          <div className="card-elevated text-center py-16">
            <Users className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
            <h3 className="text-lg font-medium text-foreground mb-2">No submissions yet</h3>
            <p className="text-muted-foreground">Start solving problems to appear on the leaderboard!</p>
          </div>
        )}
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth, UserRole } from '@/contexts/AuthContext';
import { Code2, Eye, EyeOff, AlertCircle } from 'lucide-react';

export default function Login() {
  const [isSignup, setIsSignup] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<UserRole>('student');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const { login, signup, user, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (isAuthenticated && user) {
      const dashboardPaths: Record<UserRole, string> = {
        teacher: '/teacher/dashboard',
        student: '/student/dashboard',
        professional: '/professional/dashboard',
        admin: '/teacher/dashboard',
      };
      navigate(dashboardPaths[user.role] || '/');
    }
  }, [isAuthenticated, user, navigate]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isSignup) {
        if (!name.trim()) {
          setError('Please enter your name');
          setLoading(false);
          return;
        }
        const result = await signup(email, password, name, role);
        if (!result.success) {
          setError(result.error || 'Signup failed');
        }
      } else {
        const result = await login(email, password);
        if (!result.success) {
          setError(result.error || 'Invalid email or password');
        }
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-background flex">
      {/* Left side - Branding */}
      <div className="hidden lg:flex lg:w-1/2 bg-primary p-12 flex-col justify-between">
        <div>
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-primary-foreground/20 rounded-xl flex items-center justify-center">
              <Code2 className="w-7 h-7 text-primary-foreground" />
            </div>
            <span className="text-2xl font-bold text-primary-foreground">CodeHub</span>
          </div>
        </div>

        <div className="space-y-6">
          <h1 className="text-4xl font-bold text-primary-foreground leading-tight">
            Master coding with<br />interactive assessments
          </h1>
          <p className="text-primary-foreground/80 text-lg max-w-md">
            Join thousands of students, teachers, and professionals improving their coding skills every day.
          </p>

          <div className="flex gap-8 pt-4">
            <div>
              <p className="text-3xl font-bold text-primary-foreground">10K+</p>
              <p className="text-primary-foreground/70 text-sm">Active Users</p>
            </div>
            <div>
              <p className="text-3xl font-bold text-primary-foreground">500+</p>
              <p className="text-primary-foreground/70 text-sm">Assessments</p>
            </div>
            <div>
              <p className="text-3xl font-bold text-primary-foreground">50+</p>
              <p className="text-primary-foreground/70 text-sm">Languages</p>
            </div>
          </div>
        </div>

        <p className="text-primary-foreground/60 text-sm">
          © 2024 CodeHub. All rights reserved.
        </p>
      </div>

      {/* Right side - Form */}
      <div className="flex-1 flex items-center justify-center p-8">
        <div className="w-full max-w-md">
          {/* Mobile logo */}
          <div className="lg:hidden flex items-center justify-center gap-2 mb-8">
            <div className="w-10 h-10 bg-primary rounded-lg flex items-center justify-center">
              <Code2 className="w-6 h-6 text-primary-foreground" />
            </div>
            <span className="text-xl font-bold text-foreground">CodeHub</span>
          </div>

          <div className="text-center mb-8">
            <h2 className="text-2xl font-bold text-foreground">
              {isSignup ? 'Create your account' : 'Welcome back'}
            </h2>
            <p className="text-muted-foreground mt-2">
              {isSignup
                ? 'Start your coding journey today'
                : 'Sign in to continue to CodeHub'}
            </p>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-error-light rounded-lg flex items-center gap-3 text-error">
              <AlertCircle className="w-5 h-5 flex-shrink-0" />
              <span className="text-sm">{error}</span>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {isSignup && (
              <div>
                <label className="label-text">Full Name</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="input-field"
                  placeholder="John Doe"
                  required
                />
              </div>
            )}

            <div>
              <label className="label-text">Email Address</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="input-field"
                placeholder="you@example.com"
                required
              />
            </div>

            <div>
              <label className="label-text">Password</label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="input-field pr-12"
                  placeholder="••••••••"
                  required
                  minLength={6}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                >
                  {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                </button>
              </div>
            </div>

            {isSignup && (
              <div>
                <label className="label-text">I am a...</label>
                <div className="grid grid-cols-3 gap-3">
                  {(['student', 'teacher', 'professional'] as UserRole[]).map((r) => (
                    <button
                      key={r}
                      type="button"
                      onClick={() => setRole(r)}
                      className={`py-3 px-4 rounded-lg border-2 text-sm font-medium capitalize transition-all ${
                        role === r
                          ? 'border-primary bg-primary/5 text-primary'
                          : 'border-border text-muted-foreground hover:border-primary/50'
                      }`}
                    >
                      {r}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full btn-primary py-3 text-base disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'Please wait...' : isSignup ? 'Create Account' : 'Sign In'}
            </button>
          </form>

          <p className="mt-6 text-center text-sm text-muted-foreground">
            {isSignup ? 'Already have an account?' : "Don't have an account?"}{' '}
            <button
              onClick={() => {
                setIsSignup(!isSignup);
                setError('');
              }}
              className="text-primary font-medium hover:underline"
            >
              {isSignup ? 'Sign in' : 'Sign up'}
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useData } from '@/contexts/DataContext';
import { supabase } from '@/integrations/supabase/client';
import { Navbar } from '@/components/Navbar';
import { User, Mail, Shield, Calendar, Save, CheckCircle, TrendingUp, Code, Target } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

export default function Profile() {
  const { user } = useAuth();
  const { getStudentSubmissions, assessments } = useData();
  const { toast } = useToast();
  const [name, setName] = useState(user?.name || '');
  const [saving, setSaving] = useState(false);

  const mySubmissions = user ? getStudentSubmissions(user.id) : [];
  const correctSubmissions = mySubmissions.filter(s => s.is_correct).length;
  const uniqueAssessments = new Set(mySubmissions.map(s => s.assessment_id)).size;
  const accuracy = mySubmissions.length > 0 ? (correctSubmissions / mySubmissions.length) * 100 : 0;

  const handleSave = async () => {
    if (!user || !name.trim()) return;
    setSaving(true);

    const { error } = await supabase
      .from('profiles')
      .update({ name: name.trim() })
      .eq('user_id', user.id);

    if (error) {
      toast({ title: 'Error', description: 'Failed to update profile', variant: 'destructive' });
    } else {
      toast({ title: 'Profile updated', description: 'Your name has been updated successfully' });
    }
    setSaving(false);
  };

  // Language stats
  const languageStats = mySubmissions.reduce((acc, s) => {
    const lang = s.language || 'Unknown';
    if (!acc[lang]) acc[lang] = { total: 0, correct: 0 };
    acc[lang].total++;
    if (s.is_correct) acc[lang].correct++;
    return acc;
  }, {} as Record<string, { total: number; correct: number }>);

  return (
    <>
      <Navbar />
      <div className="page-container">
        <h1 className="section-title">My Profile</h1>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Profile Info */}
          <div className="card-elevated">
            <div className="text-center mb-6">
              <div className="w-20 h-20 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-4">
                <span className="text-3xl font-bold text-primary">{user?.name?.charAt(0)?.toUpperCase()}</span>
              </div>
              <span className="px-3 py-1 bg-secondary rounded-full text-sm font-medium capitalize text-foreground">
                {user?.role}
              </span>
            </div>

            <div className="space-y-4">
              <div>
                <label className="label-text flex items-center gap-2"><User className="w-4 h-4" />Full Name</label>
                <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="input-field" />
              </div>
              <div>
                <label className="label-text flex items-center gap-2"><Mail className="w-4 h-4" />Email</label>
                <input type="email" value={user?.email || ''} className="input-field opacity-60" readOnly />
              </div>
              <div>
                <label className="label-text flex items-center gap-2"><Shield className="w-4 h-4" />Role</label>
                <input type="text" value={user?.role || ''} className="input-field opacity-60 capitalize" readOnly />
              </div>
              <button onClick={handleSave} disabled={saving} className="w-full btn-primary flex items-center justify-center gap-2">
                <Save className="w-4 h-4" />
                {saving ? 'Saving...' : 'Save Changes'}
              </button>
            </div>
          </div>

          {/* Stats */}
          <div className="lg:col-span-2 space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="stat-card text-center">
                <Code className="w-6 h-6 text-primary mx-auto mb-2" />
                <p className="text-2xl font-bold text-foreground">{mySubmissions.length}</p>
                <p className="text-sm text-muted-foreground">Submissions</p>
              </div>
              <div className="stat-card text-center">
                <CheckCircle className="w-6 h-6 text-easy mx-auto mb-2" />
                <p className="text-2xl font-bold text-easy">{correctSubmissions}</p>
                <p className="text-sm text-muted-foreground">Solved</p>
              </div>
              <div className="stat-card text-center">
                <Target className="w-6 h-6 text-warning mx-auto mb-2" />
                <p className="text-2xl font-bold text-foreground">{accuracy.toFixed(0)}%</p>
                <p className="text-sm text-muted-foreground">Accuracy</p>
              </div>
              <div className="stat-card text-center">
                <TrendingUp className="w-6 h-6 text-primary mx-auto mb-2" />
                <p className="text-2xl font-bold text-foreground">{uniqueAssessments}</p>
                <p className="text-sm text-muted-foreground">Assessments</p>
              </div>
            </div>

            {/* Language breakdown */}
            <div className="card-elevated">
              <h2 className="text-lg font-semibold text-foreground mb-4">Language Breakdown</h2>
              {Object.keys(languageStats).length > 0 ? (
                <div className="space-y-3">
                  {Object.entries(languageStats)
                    .sort(([, a], [, b]) => b.total - a.total)
                    .map(([lang, stats]) => {
                      const pct = stats.total > 0 ? (stats.correct / stats.total) * 100 : 0;
                      return (
                        <div key={lang}>
                          <div className="flex items-center justify-between text-sm mb-1">
                            <span className="font-medium text-foreground">{lang}</span>
                            <span className="text-muted-foreground">{stats.correct}/{stats.total} solved ({pct.toFixed(0)}%)</span>
                          </div>
                          <div className="h-2 bg-secondary rounded-full overflow-hidden">
                            <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${pct}%` }} />
                          </div>
                        </div>
                      );
                    })}
                </div>
              ) : (
                <p className="text-muted-foreground text-center py-8">No submissions yet. Start solving problems!</p>
              )}
            </div>

            {/* Recent Activity */}
            <div className="card-elevated">
              <h2 className="text-lg font-semibold text-foreground mb-4">Recent Submissions</h2>
              {mySubmissions.length > 0 ? (
                <div className="space-y-2">
                  {mySubmissions.slice(0, 10).map((sub) => {
                    const assessment = assessments.find(a => a.id === sub.assessment_id);
                    return (
                      <div key={sub.id} className="flex items-center justify-between p-3 rounded-lg bg-secondary/50">
                        <div className="flex items-center gap-3">
                          {sub.is_correct ? <CheckCircle className="w-5 h-5 text-easy" /> : <Target className="w-5 h-5 text-error" />}
                          <div>
                            <p className="font-medium text-foreground text-sm">{assessment?.title || 'Assessment'}</p>
                            <p className="text-xs text-muted-foreground">{new Date(sub.created_at).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <span className={`text-xs font-medium px-2 py-1 rounded ${sub.is_correct ? 'bg-success-light text-easy' : 'bg-error-light text-error'}`}>
                          {sub.score || 0}%
                        </span>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <p className="text-muted-foreground text-center py-8">No activity yet</p>
              )}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { useData, Question } from '@/contexts/DataContext';
import { CodeEditor } from '@/components/CodeEditor';
import { supabase } from '@/integrations/supabase/client';
import { ArrowLeft, Clock, CheckCircle, XCircle, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';

export default function SolveAssessment() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { addSubmission, getAssessmentWithQuestions } = useData();


// eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [assessment, setAssessment] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [timeRemaining, setTimeRemaining] = useState<number | null>(null);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [results, setResults] = useState<Record<string, { passed: boolean; details?: any }>>({});
  const [showResults, setShowResults] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (id) {
      getAssessmentWithQuestions(id).then(data => {
        setAssessment(data);
        if (data?.time_limit) setTimeRemaining(data.time_limit * 60);
        setLoading(false);
      });
    }
  }, [id, getAssessmentWithQuestions]);

  useEffect(() => {
    if (timeRemaining === null || timeRemaining <= 0) return;
    const timer = setInterval(() => {
      setTimeRemaining(prev => {
        if (prev === null || prev <= 1) { clearInterval(timer); setShowResults(true); return 0; }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [timeRemaining]);

  if (loading) return <div className="page-container flex items-center justify-center min-h-screen"><Loader2 className="w-8 h-8 animate-spin text-primary" /></div>;

  if (!assessment || !assessment.questions?.length) {
    return (
      <div className="page-container">
        <div className="card-elevated text-center py-12">
          <p className="text-muted-foreground">Assessment not found or has no questions</p>
          <button onClick={() => navigate('/student/assessments')} className="btn-primary mt-4">Back to Assessments</button>
        </div>
      </div>
    );
  }

  const currentQuestion: Question = assessment.questions[currentQuestionIndex];
  const totalQuestions = assessment.questions.length;

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleSubmit = async (code: string) => {
    if (!user || !currentQuestion || submitting) return;
    setSubmitting(true);

    const testCases = currentQuestion.test_cases || [];
    let isCorrect = false;
    let passedCount = 0;
    let score = 0;
    let outputText = '';
    let executionTime = 0;

    try {
      // Call evaluate-code edge function for real test case evaluation
      const { data, error } = await supabase.functions.invoke('evaluate-code', {
        body: {
          code,
          language: (currentQuestion.language || assessment.language).toLowerCase(),
          test_cases: testCases,
        },
      });

      if (error) throw error;

      if (data) {
        isCorrect = data.is_correct || false;
        passedCount = data.passed || 0;
        score = data.score || 0;
        executionTime = data.execution_time_ms || 0;

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const resultDetails = (data.results || []) as any[];
        outputText = resultDetails
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          .map((r: any, i: number) => `Test ${i + 1}: ${r.passed ? '✅ Passed' : `❌ Failed (expected: ${r.expected}, got: ${r.actual})`}`)
          .join('\n');
        if (!outputText) outputText = isCorrect ? 'All test cases passed!' : 'Some test cases failed.';
      }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    } catch (err: any) {
      // Fallback if edge function fails
      outputText = `Evaluation error: ${err.message || 'Could not evaluate code'}`;
    }

    await addSubmission({
      assessment_id: assessment.id,
      question_id: currentQuestion.id,
      code,
      language: currentQuestion.language || assessment.language,
      is_correct: isCorrect,
      score,
      passed_test_cases: passedCount,
      total_test_cases: testCases.length,
      output: outputText,
      status: 'completed',
    });

    setResults(prev => ({ ...prev, [currentQuestion.id]: { passed: isCorrect, details: { score, passedCount, total: testCases.length, executionTime } } }));
    setSubmitting(false);

    if (currentQuestionIndex < totalQuestions - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    } else {
      setShowResults(true);
    }
  };

  if (showResults) {
    const correctCount = Object.values(results).filter(r => r.passed).length;
    const totalAnswered = Object.keys(results).length;

    return (
      <div className="page-container">
        <div className="max-w-2xl mx-auto">
          <div className="card-elevated text-center">
            <div className={`w-20 h-20 mx-auto mb-6 rounded-full flex items-center justify-center ${correctCount / Math.max(totalAnswered, 1) >= 0.7 ? 'bg-success-light' : 'bg-warning-light'}`}>
              {correctCount / Math.max(totalAnswered, 1) >= 0.7 ? <CheckCircle className="w-10 h-10 text-easy" /> : <XCircle className="w-10 h-10 text-warning" />}
            </div>
            <h1 className="text-2xl font-bold text-foreground mb-2">Assessment Complete!</h1>
            <p className="text-muted-foreground mb-6">{assessment.title}</p>
            <div className="grid grid-cols-3 gap-4 mb-8 p-6 bg-secondary/50 rounded-lg">
              <div><p className="text-3xl font-bold text-easy">{correctCount}</p><p className="text-sm text-muted-foreground">Correct</p></div>
              <div><p className="text-3xl font-bold text-error">{totalAnswered - correctCount}</p><p className="text-sm text-muted-foreground">Incorrect</p></div>
              <div><p className="text-3xl font-bold text-foreground">{totalAnswered > 0 ? ((correctCount / totalAnswered) * 100).toFixed(0) : 0}%</p><p className="text-sm text-muted-foreground">Accuracy</p></div>
            </div>
            <div className="flex gap-4 justify-center">
              <button onClick={() => navigate('/student/assessments')} className="btn-outline">Back to Assessments</button>
              <button onClick={() => navigate('/student/dashboard')} className="btn-primary">View Dashboard</button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="bg-card border-b border-border sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => navigate('/student/assessments')} className="text-muted-foreground hover:text-foreground transition-colors"><ArrowLeft className="w-5 h-5" /></button>
            <div><h1 className="font-semibold text-foreground">{assessment.title}</h1><p className="text-sm text-muted-foreground">Question {currentQuestionIndex + 1} of {totalQuestions}</p></div>
          </div>
          <div className="flex items-center gap-4">
            {timeRemaining !== null && (
              <div className={`flex items-center gap-2 px-3 py-1.5 rounded-lg ${timeRemaining < 300 ? 'bg-error-light text-error' : 'bg-secondary text-foreground'}`}>
                <Clock className="w-4 h-4" /><span className="font-mono font-medium">{formatTime(timeRemaining)}</span>
              </div>
            )}
            <div className="flex gap-1">
              {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
              {assessment.questions.map((_: any, i: number) => (
                <div key={i} className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm font-medium cursor-pointer ${i === currentQuestionIndex ? 'bg-primary text-primary-foreground' : results[assessment.questions[i].id] !== undefined ? results[assessment.questions[i].id].passed ? 'bg-success-light text-easy' : 'bg-error-light text-error' : 'bg-secondary text-muted-foreground'}`} onClick={() => setCurrentQuestionIndex(i)}>{i + 1}</div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-6">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="card-elevated">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-foreground">{currentQuestion.title}</h2>
            </div>
            <div className="prose prose-sm max-w-none text-foreground"><p className="whitespace-pre-wrap">{currentQuestion.description}</p></div>
            {currentQuestion.test_cases && currentQuestion.test_cases.length > 0 && (
              <div className="mt-6 pt-6 border-t border-border">
                <h3 className="text-sm font-semibold text-foreground mb-3">Example Test Cases</h3>
                <div className="space-y-3">
                  {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                  {currentQuestion.test_cases.slice(0, 2).map((tc: any, i: number) => (
                    <div key={i} className="bg-code rounded-lg p-3 text-sm font-mono">
                      <div className="text-muted-foreground">Input: <span className="text-foreground">{tc.input}</span></div>
                      <div className="text-muted-foreground">Output: <span className="text-easy">{tc.expectedOutput}</span></div>
                    </div>
                  ))}
                </div>
              </div>
            )}
            {results[currentQuestion.id] && (
              <div className="mt-6 pt-6 border-t border-border">
                <h3 className="text-sm font-semibold text-foreground mb-2">Result</h3>
                <div className={`p-3 rounded-lg text-sm ${results[currentQuestion.id].passed ? 'bg-success-light text-easy' : 'bg-error-light text-error'}`}>
                  {results[currentQuestion.id].passed ? '✅ All test cases passed!' : `❌ ${results[currentQuestion.id].details?.passedCount || 0}/${results[currentQuestion.id].details?.total || 0} test cases passed`}
                  {results[currentQuestion.id].details?.executionTime > 0 && (
                    <span className="ml-2 text-muted-foreground">({results[currentQuestion.id].details.executionTime}ms)</span>
                  )}
                </div>
              </div>
            )}
            <div className="mt-6 pt-6 border-t border-border flex justify-between">
              <button onClick={() => setCurrentQuestionIndex(prev => Math.max(0, prev - 1))} disabled={currentQuestionIndex === 0} className="btn-outline flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"><ChevronLeft className="w-4 h-4" />Previous</button>
              <button onClick={() => setCurrentQuestionIndex(prev => Math.min(totalQuestions - 1, prev + 1))} disabled={currentQuestionIndex === totalQuestions - 1} className="btn-outline flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">Next<ChevronRight className="w-4 h-4" /></button>
            </div>
          </div>
          <div className="card-elevated p-0 overflow-hidden">
            <CodeEditor
              initialCode={currentQuestion.starter_code || ''}
              language={currentQuestion.language || assessment.language}
              onSubmit={handleSubmit}
              submitting={submitting}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { useData } from '@/contexts/DataContext';
import { Plus, Trash2, Sparkles, Loader2, CheckCircle } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';

interface QuestionInput {
  title: string;
  description: string;
  starter_code: string;
  language: string;
  test_cases: { input: string; expectedOutput: string }[];
}

export default function CreateAssessment() {
  const { user } = useAuth();
  const { addAssessment } = useData();
  const navigate = useNavigate();

  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('easy');
  const [language, setLanguage] = useState('JavaScript');
  const [timeLimit, setTimeLimit] = useState<number | undefined>();
  const [isPublished, setIsPublished] = useState(false);
  const [questions, setQuestions] = useState<QuestionInput[]>([]);
  const [submitting, setSubmitting] = useState(false);

  // AI generation states
  const [showAIPanel, setShowAIPanel] = useState(false);
  const [aiDifficulty, setAiDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');
  const [aiLanguage, setAiLanguage] = useState('JavaScript');
  const [aiReference, setAiReference] = useState('LeetCode');
  const [aiGenerating, setAiGenerating] = useState(false);
  const [aiSuccess, setAiSuccess] = useState(false);

  const languages = ['JavaScript', 'Python', 'Java', 'C++', 'C', 'Go', 'Rust', 'TypeScript'];
  const references = ['LeetCode', 'HackerRank', 'CodeChef', 'Codeforces', 'GeeksForGeeks'];

  const addQuestion = () => {
    setQuestions([
      ...questions,
      {
        title: '',
        description: '',
        starter_code: getStarterCode(language),
        language,
        test_cases: [{ input: '', expectedOutput: '' }],
      },
    ]);
  };

  const getStarterCode = (lang: string) => {
    const templates: Record<string, string> = {
      JavaScript: `function solution(input) {\n  // Write your code here\n  \n}`,
      Python: `def solution(input):\n    # Write your code here\n    pass`,
      Java: `public class Solution {\n    public static void main(String[] args) {\n        // Write your code here\n    }\n}`,
      'C++': `#include <iostream>\nusing namespace std;\n\nint main() {\n    // Write your code here\n    return 0;\n}`,
    };
    return templates[lang] || templates.JavaScript;
  };

  const updateQuestion = (index: number, updates: Partial<QuestionInput>) => {
    const updated = [...questions];
    updated[index] = { ...updated[index], ...updates };
    setQuestions(updated);
  };

  const removeQuestion = (index: number) => {
    setQuestions(questions.filter((_, i) => i !== index));
  };

  const generateWithAI = async () => {
    setAiGenerating(true);

    try {
      const { data, error } = await supabase.functions.invoke('generate-question', {
        body: { difficulty: aiDifficulty, language: aiLanguage, reference: aiReference },
      });

      if (error) throw error;

      if (data?.question) {
        setQuestions([...questions, data.question]);
      }
    } catch (err) {
      // Fallback to simulated generation
      const generatedQuestion: QuestionInput = {
        title: aiDifficulty === 'easy' ? 'Sum of Array' : aiDifficulty === 'medium' ? 'Two Sum Problem' : 'Merge Intervals',
        description: aiDifficulty === 'easy'
          ? 'Given an array of integers, return the sum of all elements.'
          : aiDifficulty === 'medium'
          ? 'Given an array of integers and a target, return indices of two numbers that add up to the target.'
          : 'Given a collection of intervals, merge all overlapping intervals.',
        starter_code: getStarterCode(aiLanguage),
        language: aiLanguage,
        test_cases: [
          { input: aiDifficulty === 'easy' ? '[1, 2, 3]' : '[2, 7, 11, 15], 9', expectedOutput: aiDifficulty === 'easy' ? '6' : '[0, 1]' },
          { input: aiDifficulty === 'easy' ? '[10, 20, 30]' : '[3, 2, 4], 6', expectedOutput: aiDifficulty === 'easy' ? '60' : '[1, 2]' },
        ],
      };
      setQuestions([...questions, generatedQuestion]);
    }

    setAiGenerating(false);
    setAiSuccess(true);
    setTimeout(() => setAiSuccess(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || questions.length === 0) return;

    setSubmitting(true);

    await addAssessment({
      title,
      description,
      difficulty,
      language,
      time_limit: timeLimit,
      is_published: isPublished,
      questions: questions.map((q, i) => ({
        ...q,
        sort_order: i,
      })),
    });

    setSubmitting(false);
    navigate('/teacher/assessments');
  };

  return (
    <div className="page-container">
      <div className="max-w-4xl mx-auto">
        <h1 className="section-title">Create Assessment</h1>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Basic Info */}
          <div className="card-elevated">
            <h2 className="text-lg font-semibold text-foreground mb-4">Basic Information</h2>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <label className="label-text">Title</label>
                <input
                  type="text"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  className="input-field"
                  placeholder="e.g., JavaScript Fundamentals"
                  required
                />
              </div>

              <div className="md:col-span-2">
                <label className="label-text">Description</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="input-field min-h-[100px] resize-none"
                  placeholder="Describe what this assessment covers..."
                  required
                />
              </div>

              <div>
                <label className="label-text">Difficulty</label>
                <select
                  value={difficulty}
                  onChange={(e) => setDifficulty(e.target.value as 'easy' | 'medium' | 'hard')}
                  className="select-field"
                >
                  <option value="easy">Easy</option>
                  <option value="medium">Medium</option>
                  <option value="hard">Hard</option>
                </select>
              </div>

              <div>
                <label className="label-text">Language</label>
                <select
                  value={language}
                  onChange={(e) => setLanguage(e.target.value)}
                  className="select-field"
                >
                  {languages.map((lang) => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="label-text">Time Limit (minutes, optional)</label>
                <input
                  type="number"
                  value={timeLimit || ''}
                  onChange={(e) => setTimeLimit(e.target.value ? parseInt(e.target.value) : undefined)}
                  className="input-field"
                  placeholder="No limit"
                  min={5}
                  max={180}
                />
              </div>

              <div className="flex items-center gap-3 pt-6">
                <input
                  type="checkbox"
                  id="isPublished"
                  checked={isPublished}
                  onChange={(e) => setIsPublished(e.target.checked)}
                  className="w-4 h-4 rounded border-border text-primary focus:ring-primary"
                />
                <label htmlFor="isPublished" className="text-sm font-medium text-foreground">
                  Publish immediately
                </label>
              </div>
            </div>
          </div>

          {/* AI Generation */}
          <div className="card-elevated">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-foreground">Questions</h2>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setShowAIPanel(!showAIPanel)}
                  className="flex items-center gap-2 btn-secondary"
                >
                  <Sparkles className="w-4 h-4" />
                  AI Generate
                </button>
                <button
                  type="button"
                  onClick={addQuestion}
                  className="flex items-center gap-2 btn-primary"
                >
                  <Plus className="w-4 h-4" />
                  Add Manual
                </button>
              </div>
            </div>

            {showAIPanel && (
              <div className="bg-secondary/50 rounded-lg p-4 mb-6 border border-border">
                <h3 className="font-medium text-foreground mb-3 flex items-center gap-2">
                  <Sparkles className="w-4 h-4 text-primary" />
                  AI Question Generator
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                  <div>
                    <label className="label-text">Difficulty</label>
                    {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                    <select value={aiDifficulty} onChange={(e) => setAiDifficulty(e.target.value as any)} className="select-field">
                      <option value="easy">Easy</option>
                      <option value="medium">Medium</option>
                      <option value="hard">Hard</option>
                    </select>
                  </div>
                  <div>
                    <label className="label-text">Language</label>
                    <select value={aiLanguage} onChange={(e) => setAiLanguage(e.target.value)} className="select-field">
                      {languages.map((lang) => (<option key={lang} value={lang}>{lang}</option>))}
                    </select>
                  </div>
                  <div>
                    <label className="label-text">Reference Style</label>
                    <select value={aiReference} onChange={(e) => setAiReference(e.target.value)} className="select-field">
                      {references.map((ref) => (<option key={ref} value={ref}>{ref}</option>))}
                    </select>
                  </div>
                </div>
                <button type="button" onClick={generateWithAI} disabled={aiGenerating} className="btn-primary flex items-center gap-2">
                  {aiGenerating ? (<><Loader2 className="w-4 h-4 animate-spin" />Generating...</>) : aiSuccess ? (<><CheckCircle className="w-4 h-4" />Generated!</>) : (<><Sparkles className="w-4 h-4" />Generate Question</>)}
                </button>
              </div>
            )}

            {questions.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <p>No questions added yet. Use the buttons above to add questions.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {questions.map((question, index) => (
                  <div key={index} className="border border-border rounded-lg p-4">
                    <div className="flex items-start justify-between mb-4">
                      <h4 className="font-medium text-foreground">Question {index + 1}</h4>
                      <button type="button" onClick={() => removeQuestion(index)} className="text-muted-foreground hover:text-error transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>

                    <div className="grid gap-4">
                      <div>
                        <label className="label-text">Question Title</label>
                        <input type="text" value={question.title} onChange={(e) => updateQuestion(index, { title: e.target.value })} className="input-field" placeholder="e.g., Reverse a String" required />
                      </div>
                      <div>
                        <label className="label-text">Description</label>
                        <textarea value={question.description} onChange={(e) => updateQuestion(index, { description: e.target.value })} className="input-field min-h-[80px] resize-none" placeholder="Describe the problem..." required />
                      </div>
                      <div>
                        <label className="label-text">Starter Code</label>
                        <textarea value={question.starter_code} onChange={(e) => updateQuestion(index, { starter_code: e.target.value })} className="input-field font-mono text-sm min-h-[120px] resize-none" />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Submit */}
          <div className="flex justify-end gap-4">
            <button type="button" onClick={() => navigate('/teacher/assessments')} className="btn-outline">Cancel</button>
            <button type="submit" disabled={!title || !description || questions.length === 0 || submitting} className="btn-primary disabled:opacity-50 disabled:cursor-not-allowed">
              {submitting ? 'Creating...' : 'Create Assessment'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
